import { MMKV } from 'react-native-mmkv';

export const storage = new MMKV({ id: 'marketify' });

export const STORAGE_KEYS = {
  jwt: 'marketify.jwt',
  user: 'marketify.user',
} as const;

import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
  type ReactNode,
} from 'react';
import type { Database } from '@/types/supabase';
import { storage, STORAGE_KEYS } from './storage';

export type AuthUser = Database['public']['Tables']['users']['Row'];
export type AuthRole = Database['public']['Enums']['user_role'];

type AuthContextValue = {
  user: AuthUser | null;
  role: AuthRole | null;
  signIn: (token: string, user: AuthUser) => void;
  signOut: () => void;
};

const AuthContext = createContext<AuthContextValue | null>(null);

function readPersistedUser(): AuthUser | null {
  const raw = storage.getString(STORAGE_KEYS.user);
  if (!raw) return null;
  try {
    return JSON.parse(raw) as AuthUser;
  } catch {
    storage.delete(STORAGE_KEYS.user);
    storage.delete(STORAGE_KEYS.jwt);
    return null;
  }
}

export function AuthProvider({ children }: { children: ReactNode }) {
  // MMKV reads are synchronous, so we can hydrate during initial render and
  // avoid a loading flash on boot.
  const [user, setUser] = useState<AuthUser | null>(() => {
    const hasToken = storage.contains(STORAGE_KEYS.jwt);
    return hasToken ? readPersistedUser() : null;
  });

  const signIn = useCallback((token: string, nextUser: AuthUser) => {
    storage.set(STORAGE_KEYS.jwt, token);
    storage.set(STORAGE_KEYS.user, JSON.stringify(nextUser));
    setUser(nextUser);
  }, []);

  const signOut = useCallback(() => {
    storage.delete(STORAGE_KEYS.jwt);
    storage.delete(STORAGE_KEYS.user);
    setUser(null);
  }, []);

  const value = useMemo<AuthContextValue>(
    () => ({
      user,
      role: user?.role ?? null,
      signIn,
      signOut,
    }),
    [user, signIn, signOut],
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth(): AuthContextValue {
  const ctx = useContext(AuthContext);
  if (!ctx) {
    throw new Error('useAuth must be used inside an AuthProvider.');
  }
  return ctx;
}

