    const hasToken = storage.contains(STORAGE_KEYS.jwt);
    return hasToken ? readPersistedUser() : null;
  });

  const signIn = useCallback((token: string, nextUser: AuthUser) => {
    storage.set(STORAGE_KEYS.jwt, token);
    storage.set(STORAGE_KEYS.user, JSON.stringify(nextUser));
    setUser(nextUser);
  }, []);

  const signOut = useCallback(() => {
    storage.remove(STORAGE_KEYS.jwt);
    storage.remove(STORAGE_KEYS.user);
    setUser(null);
  }, []);

  const value = useMemo<AuthContextValue>(
    () => ({
      user,
      role: user?.role ?? null,
      signIn,
      signOut,
    }),
    [user, signIn, signOut],
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth(): AuthContextValue {
  const ctx = useContext(AuthContext);
  if (!ctx) {
    throw new Error('useAuth must be used inside an AuthProvider.');
  }
  return ctx;
}

import 'react-native-url-polyfill/auto';
import { createClient } from '@supabase/supabase-js';
import Constants from 'expo-constants';
import type { Database } from '@/types/supabase';
import { storage, STORAGE_KEYS } from './storage';

type Extra = {
  SUPABASE_URL?: string;
  SUPABASE_ANON_KEY?: string;
};

const extra = (Constants.expoConfig?.extra ?? {}) as Extra;

if (!extra.SUPABASE_URL || !extra.SUPABASE_ANON_KEY) {
  throw new Error(
    'Missing SUPABASE_URL or SUPABASE_ANON_KEY. Populate .env and rebuild the Expo config.',
  );
}

// Inject our custom-issued Marketify JWT from MMKV on every request. Reading on
// each fetch is the "refresh on auth context change" in the story AC — signIn /
// signOut mutate MMKV and the next request picks it up without recreating the
// client. When there is no JWT the anon key in the default headers is still sent.
const marketifyFetch: typeof fetch = (input, init) => {
  const token = storage.getString(STORAGE_KEYS.jwt);
  if (!token) {
    return fetch(input, init);
  }
  const headers = new Headers(init?.headers);
  headers.set('Authorization', `Bearer ${token}`);
  return fetch(input, { ...init, headers });
};

export const supabase = createClient<Database>(extra.SUPABASE_URL, extra.SUPABASE_ANON_KEY, {
  auth: {
    // We issue our own JWT via edge functions — disable Supabase Auth's
    // session handling so it doesn't fight the Authorization header above.
    persistSession: false,
    autoRefreshToken: false,
    detectSessionInUrl: false,
  },
  global: {
    fetch: marketifyFetch,
  },
});

